function summarizeMetrics(seriesData) {
  if (!seriesData || !seriesData.series || seriesData.series.length === 0) {
    return { available: false };
  }
  const points = seriesData.series[0].pointlist || [];
  const values = points.map(p => p[1]).filter(v => v !== null && !isNaN(v));
  if (values.length === 0) return { available: false };
  const avg = values.reduce((a, b) => a + b, 0) / values.length;
  const max = Math.max(...values);
  const min = Math.min(...values);
  const firstHalf = values.slice(0, Math.floor(values.length / 2));
  const secondHalf = values.slice(Math.floor(values.length / 2));
  const avgFirst = firstHalf.reduce((a, b) => a + b, 0) / (firstHalf.length || 1);
  const avgSecond = secondHalf.reduce((a, b) => a + b, 0) / (secondHalf.length || 1);
  let trend = 'estable';
  if (avgSecond > avgFirst * 1.2) trend = 'subiendo ↗';
  else if (avgSecond < avgFirst * 0.8) trend = 'bajando ↘';
  return {
    available: true,
    avg: parseFloat(avg.toFixed(2)),
    max: parseFloat(max.toFixed(2)),
    min: parseFloat(min.toFixed(2)),
    trend,
    points_count: values.length,
  };
}

function summarizeLogs(logsData) {
  if (!logsData || !logsData.data || logsData.data.length === 0) {
    return { available: false, count: 0, samples: [] };
  }
  const logs = logsData.data.slice(0, 5);
  const samples = logs.map(l => {
    const attrs = l.attributes || {};
    const msg = (attrs.message || '').substring(0, 200);
    const ts = attrs.timestamp || '';
    const status = attrs.status || '';
    const service = attrs.service || '';
    return { timestamp: ts, status, service, message: msg };
  });
  return {
    available: true,
    count: logsData.data.length,
    samples,
  };
}

function summarizeEvents(eventsData) {
  if (!eventsData || !eventsData.events || eventsData.events.length === 0) {
    return { available: false, deploys: [], changes: [] };
  }
  const deploys = [];
  const changes = [];
  for (const ev of eventsData.events.slice(0, 10)) {
    const title = (ev.title || '').toLowerCase();
    const text = (ev.text || '').substring(0, 200);
    const item = {
      title: ev.title || '',
      text,
      date: ev.date_happened ? new Date(ev.date_happened * 1000).toISOString() : null,
      tags: ev.tags || [],
    };
    if (title.includes('deploy') || title.includes('release')) deploys.push(item);
    else changes.push(item);
  }
  return {
    available: true,
    deploys: deploys.slice(0, 3),
    changes: changes.slice(0, 3),
  };
}

function summarizeCorrelation(slackHistoryData, parsed) {
  if (!slackHistoryData || !Array.isArray(slackHistoryData) || slackHistoryData.length === 0) {
    return { available: false, similar_count: 0 };
  }
  const resource = parsed.resource;
  const r = Array.isArray(resource) ? resource[0] : (resource || '');
  const alertType = (parsed.alert_type || '').toLowerCase();
  let similarCount = 0;
  const samples = [];
  for (const msg of slackHistoryData) {
    const txt = (msg.text || msg.json?.text || '').toLowerCase();
    if (!txt) continue;
    const matchesResource = r && txt.includes(r.toLowerCase());
    const matchesType = alertType && (
      txt.includes(alertType.replace(/_/g, ' ')) ||
      (alertType === 'lambda_error' && txt.includes('lambda')) ||
      (alertType === 'ecs_cpu' && txt.includes('cpu')) ||
      (alertType === 'ecs_memory' && txt.includes('memory'))
    );
    if (matchesResource || matchesType) {
      similarCount++;
      if (samples.length < 3) {
        samples.push((msg.text || msg.json?.text || '').substring(0, 100));
      }
    }
  }
  return {
    available: true,
    similar_count: similarCount,
    samples,
  };
}

const items = $input.all();
return items.map(item => {
  const j = item.json;
  const parsed = j.parsed || {};
  const metricsSummary = summarizeMetrics(j.dd_metrics_response);
  const logsSummary = summarizeLogs(j.dd_logs_response);
  const eventsSummary = summarizeEvents(j.dd_events_response);
  const correlationSummary = summarizeCorrelation(j.slack_history_response, parsed);
  const awsHealth = j.aws_health_summary || { available: false, incidents: 0 };

  const runbookDetail = j.runbook_detail || null;
  const enrichedContext = {
    alert: parsed,
    metrics: metricsSummary,
    logs: logsSummary,
    events: eventsSummary,
    correlation: correlationSummary,
    aws_health: awsHealth,
    runbook: runbookDetail,
  };

  return {
    json: {
      ...j,
      enriched_context: enrichedContext,
      runbook_detail: runbookDetail,
      claude_prompt: buildClaudePrompt(enrichedContext),
    },
  };
});

function buildClaudePrompt(ctx) {
  const a = ctx.alert;
  const m = ctx.metrics;
  const l = ctx.logs;
  const e = ctx.events;
  const c = ctx.correlation;
  const h = ctx.aws_health;

  let prompt = `Eres un ingeniero N1 de NOC experto. Analiza esta alerta de producción y da un diagnóstico breve, accionable y en español. Responde SOLO con el análisis (2-4 oraciones), sin saludos ni despedidas.

ALERTA:
- Tipo: ${a.alert_type}
- Estado: ${a.state}
- Recurso: ${Array.isArray(a.resource) ? a.resource.join(', ') : a.resource}
- Región: ${a.region || 'N/A'}
- Valor: ${a.metric_value} (umbral: ${a.threshold})
`;

  if (m.available) {
    prompt += `\nMÉTRICA ÚLTIMOS 30 MIN:
- Promedio: ${m.avg}
- Máximo: ${m.max}
- Tendencia: ${m.trend}
`;
  } else {
        prompt += '\nMETRICA: No disponible para este tipo de alerta (no hagas suposiciones sobre valores numericos).';
  }

  if (l.available && l.samples.length > 0) {
    prompt += `\nLOGS RECIENTES (${l.count} en últimos 15min):`;
    l.samples.slice(0, 3).forEach(log => {
      prompt += `\n- [${log.status}] ${log.message.substring(0, 150)}`;
    });
  }

  if (e.available && e.deploys.length > 0) {
    prompt += `\n\nDEPLOYS/CAMBIOS RECIENTES:`;
    e.deploys.forEach(d => {
      prompt += `\n- ${d.title}`;
    });
  }

  if (c.available && c.similar_count > 0) {
    prompt += `\n\nCORRELACIÓN: ${c.similar_count} alertas similares en la última hora.`;
  }

  if (h.available && h.incidents > 0) {
    prompt += `\n\nAWS HEALTH: ${h.incidents} incidente(s) activo(s) en la región.`;
  }

  if (ctx.runbook) {
    const rb = ctx.runbook;
    prompt += `\n\nRUNBOOK APLICABLE: ${rb.id} - ${rb.nombre}`;
    if (rb.diagnostico) {
      prompt += `\nPASOS DE DIAGNÓSTICO N1 (oficiales):\n${rb.diagnostico.substring(0, 800)}`;
    }
    if (rb.accion) {
      prompt += `\n\nACCIÓN CORRECTIVA N1 (oficial):\n${rb.accion.substring(0, 500)}`;
    }
    if (rb.escalamiento) {
      prompt += `\n\nCONDICIONES DE ESCALAMIENTO (oficial):\n${rb.escalamiento.substring(0, 400)}`;
    }
  }

  prompt += `\n\nResponde en 3-5 oraciones siguiendo el runbook oficial cuando exista:
1. Causa raíz probable (correlacionando logs, deploys, métricas).
2. Pasos concretos del runbook que el ingeniero N1 debe ejecutar AHORA (cita el runbook).
3. Si debe escalar a N2 según las condiciones oficiales del runbook.
4. (Opcional) Patrón interesante que detectaste en los datos.
Sé conciso, técnico y accionable. Usa términos en español.`;
  return prompt;
}

const items = $input.all();

return items.map(item => {
  const j = item.json;
  const ctx = j.enriched_context || {};
  const a = ctx.alert || {};
  const m = ctx.metrics || {};
  const l = ctx.logs || {};
  const e = ctx.events || {};
  const c = ctx.correlation || {};
  const h = ctx.aws_health || {};
  const rb = ctx.runbook;

  // =========================
  // 🧠 IA
  // =========================
  let aiAnalysis = '_(Sin análisis IA)_';
  const resp = j.claude_response || j.gemini_response || j.ai_response;

  if (resp) {
    if (resp.candidates?.[0]?.content?.parts) {
      aiAnalysis = resp.candidates[0].content.parts.map(p => p.text || '').join('').trim();
    } else if (resp.choices?.[0]?.message?.content) {
      aiAnalysis = resp.choices[0].message.content.trim();
    } else if (resp.content?.[0]?.text) {
      aiAnalysis = resp.content[0].text.trim();
    } else if (typeof resp === 'string') {
      aiAnalysis = resp.trim();
    }
  }

  // =========================
  // 🎯 STATUS
  // =========================
  const isCritical = a.state === 'TRIGGERED' || a.state === 'RE-TRIGGERED';
  const isRecovered = a.state === 'RECOVERED';

  const icon = isRecovered ? '🟢' : isCritical ? '🔴' : '🟡';

  const severity =
    a.severity === 'ALERT' ? 'CRÍTICO' :
    a.severity === 'WARN' ? 'ADVERTENCIA' :
    'OK';

  const typeLabel = (a.alert_type || 'UNKNOWN').replace(/_/g, ' ');
  const resource = Array.isArray(a.resource) ? a.resource.join(', ') : (a.resource || 'N/A');

  // =========================
  // 📊 METRICS
  // =========================
  const metricsBlock = m.available
    ? `\n*📊 Métricas (30 min)* → avg: \`${m.avg}\` | max: \`${m.max}\` | min: \`${m.min}\` | trend: \`${m.trend}\``
    : '';

  // =========================
  // 📜 LOGS (más limpio)
  // =========================
  let logsBlock = '';
  if (l.available && l.samples?.length) {
    const samples = l.samples.slice(0, 3);

    logsBlock = `\n*📜 Logs relevantes*`;

    logsBlock += samples.map(log => {
      const t = log.timestamp?.substring(11, 19) || '??:??:??';
      const msg = (log.message || '').replace(/\n/g, ' ').substring(0, 100);
      return `\n  • \`${t}\` ${msg}`;
    }).join('');
  }

  // =========================
  // 🚀 EVENTS
  // =========================
  let eventsBlock = '';
  if (e.available && (e.deploys?.length || e.changes?.length)) {
    eventsBlock = `\n*🚀 Cambios recientes*`;

    (e.deploys || []).slice(0, 2).forEach(d => {
      eventsBlock += `\n  • Deploy: ${(d.title || '').substring(0, 90)}`;
    });

    (e.changes || []).slice(0, 2).forEach(ch => {
      eventsBlock += `\n  • Change: ${(ch.title || '').substring(0, 90)}`;
    });
  }

  // =========================
  // 🔁 CORRELATION
  // =========================
  const correlationBlock = (c.available && c.similar_count > 0)
    ? `\n*🔁 Correlación:* ${c.similar_count} alerta(s) similar(es) en 1h ${c.similar_count >= 3 ? '⚠️ patrón' : ''}`
    : '';

  // =========================
  // ☁️ AWS HEALTH
  // =========================
  const healthBlock = h.available
    ? (h.incidents > 0
      ? `\n*☁️ AWS Health:* 🔴 ${h.incidents} incidente(s) activo(s)`
      : `\n*☁️ AWS Health:* 🟢 Sin incidentes`)
    : '';

  // =========================
  // 📖 RUNBOOK
  // =========================
  let runbookBlock = '';

  if (rb) {
    runbookBlock = `\n*📖 Runbook:* ${rb.id} — ${rb.nombre || ''}`;

    if (rb.diagnostico) {
      const steps = rb.diagnostico
        .split('\n')
        .map(s => s.trim())
        .filter(Boolean)
        .slice(0, 4);

      if (steps.length) {
        runbookBlock += `\n*Checklist N1:*`;
        steps.forEach((s, i) => {
          runbookBlock += `\n  ☐ ${i + 1}. ${s.substring(0, 100)}`;
        });
      }
    }
  } else {
    runbookBlock = '\n*📖 Runbook:* _Sin runbook disponible para este tipo de alerta._';
  }

  const linkBlock = a.monitor_url
    ? `\n🔗 <${a.monitor_url}|Abrir monitor>`
    : '';

  // =========================
  // 🧠 FINAL MESSAGE (estructura tipo NOC)
  // =========================
  const message =
`${icon} *INCIDENTE AUTOMATIZADO N1*
━━━━━━━━━━━━━━━━━━━━━━
*Severidad:* ${severity}   *Estado:* ${a.state}
*Tipo:* ${typeLabel}
*Recurso:* ${resource}
*Región:* ${a.region || 'N/A'}
*Valor:* ${a.metric_value || 'N/A'}  |  Umbral: ${a.threshold || 'N/A'}
${metricsBlock}
${logsBlock}
${eventsBlock}
${correlationBlock}
${healthBlock}

*🧠 Análisis IA*
${aiAnalysis}

${runbookBlock}
${linkBlock}

_FYI:_ <@U09DURT23S6> <@U06BU9YU9J6>`;
  return {
    json: {
      ...j,
      slack_message: message,
    },
  };
});

